esqlQuery.esql:
// Alert when unindexed LDAP searches are detected.
// Unindexed searches cause full table scans and degrade performance
// for all LDAP clients (SSH logins, sudo, HBAC evaluation).
// Adjust the threshold in the final WHERE clause as needed.
FROM logs-freeipa.directory_access-*
| WHERE freeipa.directory.unindexed == true
| STATS unindexed_count = COUNT(*) BY freeipa.directory.notes
| WHERE unindexed_count >= 5
